import re

# Read pyproject.toml and extract [project.optional-dependencies] dev
with open('pyproject.toml') as f:
    content = f.read()

# Extract dev deps
in_dev = False
dev_deps = {}
for line in content.split('\n'):
    if 'dev = [' in line:
        in_dev = True
        continue
    if in_dev:
        if line.strip().startswith(']'):
            break
        if line.strip().startswith('"'):
            # Extract version constraint
            match = re.search(r'([a-z0-9\-]+)>=([0-9.]+),<(\d+)', line)
            if match:
                pkg, floor, ceil = match.groups()
                dev_deps[pkg] = (floor, ceil)

# Read requirements.txt
req_deps = {}
with open('requirements.txt') as f:
    for line in f:
        line = line.strip()
        if not line or line.startswith('#'):
            continue
        match = re.search(r'([a-z0-9\-]+)==([\d.]+)|([a-z0-9\-]+)>=([0-9.]+),<(\d+)', line)
        if match:
            if match.group(1):  # == format
                pkg, ver = match.group(1), match.group(2)
                req_deps[pkg] = ('exact', ver)
            else:  # >= format
                pkg, floor, ceil = match.group(3), match.group(4), match.group(5)
                req_deps[pkg] = (floor, ceil)

# Check alignment
print("Checking pyproject.toml [dev] vs requirements.txt:")
for pkg in sorted(dev_deps.keys()):
    if pkg in req_deps:
        pyp_floor, pyp_ceil = dev_deps[pkg]
        req_floor, req_ceil = req_deps[pkg]
        if req_floor != 'exact' and (pyp_floor != req_floor or pyp_ceil != req_ceil):
            print(f"  MISMATCH {pkg}: pyproject={pyp_floor},<{pyp_ceil} vs requirements={req_floor},<{req_ceil}")
    else:
        print(f"  TOOLING-ONLY {pkg}: {dev_deps[pkg][0]},<{dev_deps[pkg][1]} (not in requirements.txt, expected)")

print("\nChecking requirements.txt exact pins in [dev] (should have <N ceil):")
exact_pins = [pkg for pkg, (fmt, _) in req_deps.items() if fmt == 'exact' and pkg in ['black', 'ruff', 'pytest', 'pytest-cov']]
for pkg in exact_pins:
    if pkg in dev_deps:
        print(f"  {pkg}: pyproject has range {dev_deps[pkg][0]},<{dev_deps[pkg][1]}, requirements.txt has exact pin")
