# Check for any version constraint issues between requirements.txt and requirements-ci.txt
import re

with open('requirements.txt') as f:
    req_lines = f.readlines()

with open('requirements-ci.txt') as f:
    ci_lines = f.readlines()

# Parse both files
def parse_reqs(lines):
    reqs = {}
    for line in lines:
        line = line.strip()
        if not line or line.startswith('#'):
            continue
        # Extract package name and version spec
        match = re.match(r'([a-zA-Z0-9_\-]+)\[.*?\](.+)|([a-zA-Z0-9_\-]+)(.+)', line)
        if match:
            if match.group(1):
                pkg = match.group(1)
                spec = match.group(2)
            else:
                pkg = match.group(3)
                spec = match.group(4)
            reqs[pkg.lower()] = spec.strip()
    return reqs

req_dict = parse_reqs(req_lines)
ci_dict = parse_reqs(ci_lines)

print("Checking version constraints alignment:")
print("\nPackages in requirements-ci.txt:")
for pkg in sorted(ci_dict.keys()):
    ci_spec = ci_dict[pkg]
    if pkg in req_dict:
        req_spec = req_dict[pkg]
        # Check if they have compatible bounds
        if ci_spec != req_spec:
            print(f"  DIFF {pkg:20} ci={ci_spec:20} req={req_spec:20}")
        else:
            print(f"  SAME {pkg:20} {ci_spec}")
    else:
        print(f"  ONLY-CI {pkg:20} {ci_spec} (not in requirements.txt)")

print("\nPackages ONLY in requirements.txt (not in CI):")
for pkg in sorted(req_dict.keys()):
    if pkg not in ci_dict:
        print(f"  {pkg:20} {req_dict[pkg]}")
