# Check platform.yaml for any suspicious values
import yaml

with open('configs/platform.yaml') as f:
    cfg = yaml.safe_load(f)

def find_nulls(d, path=""):
    """Find all None values in a dict tree"""
    if isinstance(d, dict):
        for k, v in d.items():
            new_path = f"{path}.{k}" if path else k
            if v is None:
                yield new_path
            else:
                yield from find_nulls(v, new_path)
    elif isinstance(d, list):
        for i, v in enumerate(d):
            new_path = f"{path}[{i}]"
            yield from find_nulls(v, new_path)

print("Checking for None/null values in platform.yaml:")
nulls = list(find_nulls(cfg))
if nulls:
    print("  Found null values:")
    for path in nulls:
        print(f"    {path}")
else:
    print("  No null values (good)")

# Check for empty strings
print("\nChecking for empty strings:")
def find_empty_strings(d, path=""):
    if isinstance(d, dict):
        for k, v in d.items():
            new_path = f"{path}.{k}" if path else k
            if isinstance(v, str) and v == "":
                yield new_path
            elif isinstance(v, (dict, list)):
                yield from find_empty_strings(v, new_path)
    elif isinstance(d, list):
        for i, v in enumerate(d):
            new_path = f"{path}[{i}]"
            if isinstance(v, str) and v == "":
                yield new_path
            elif isinstance(v, (dict, list)):
                yield from find_empty_strings(v, new_path)

empties = list(find_empty_strings(cfg))
if empties:
    print("  Found empty strings:")
    for path in empties:
        print(f"    {path}")
else:
    print("  No empty strings (good)")
